}


function ask() {
    # https://djm.me/ask
    local prompt default reply

    if [ "${2:-}" = "Y" ]; then
        prompt="Y/n"
        default=Y
    elif [ "${2:-}" = "N" ]; then
        prompt="y/N"
        default=N
    else
        prompt="y/n"
        default=
    fi

    while true; do

        # Ask the question (not using "read -p" as it uses stderr not stdout)
        echo -n "$1 [$prompt] "

        # Read the answer (use /dev/tty in case stdin is redirected from somewhere else)
        read reply </dev/tty

        # Default?
        if [ -z "$reply" ]; then
            reply=$default
        fi

        # Check if the reply is valid
        case "$reply" in
            Y*|y*) return 0 ;;
            N*|n*) return 1 ;;
        esac

    done
}

function init_local_repo() {
    IFS=' ' read -r -a array <<< $(echo "deb [trusted=yes arch=amd64] file:///opt/agama-ci-prerelease-184 ./")
    CREATE_LOCAL_BKC_REPO=$(basename ${array[3]})
    WORKDIR=/opt/$CREATE_LOCAL_BKC_REPO
    URL=''

    #Parse CREATE_LOCAL_BKC_REPO
    local branch=${CREATE_LOCAL_BKC_REPO#*-ci-}

    if [ -d "${WORKDIR}" ]; then
        echo >&2 "Discovered a repository already downloaded to ${WORKDIR}"
        echo >&2 "If you want to re-initalize the repository, please remove ${WORKDIR}"
        echo >&2 "If you want to use the initalized the repository, add 'deb [trusted=yes arch=amd64] file:// ./' to /etc/apt/sources.list.d/intel-graphics.list"
        echo >&2 "Remove all entries currently in intel-graphics.list. Only 1 entry is supported at a time."
        exit 1
    fi

    mkdir -p ${WORKDIR}
    echo "Downloading packages into local repository..."
    echo "Downloading the release files now requires your IDSID username and password (without domain)."
    read -p 'Username: ' USERNAME

    # Example "$CREATE_LOCAL_BKC_REPO": 'agama-ci-embargo-ats-132'
    # Another "$CREATE_LOCAL_BKC_REPO": 'gfx-driver-ci-poweron_0b-176' - use the repo to figure out the URL. Could be fragile, but I see no other way.
    if [[ "$CREATE_LOCAL_BKC_REPO" =~ "agama" ]]; then
        URL="https://gfx-assets-build.fm.intel.com/artifactory/api/archive/download/agama-builds/ci/${branch%-*}/$CREATE_LOCAL_BKC_REPO/artifacts/linux/ubuntu/20.04?archiveType=tgz"
    elif [[ "$CREATE_LOCAL_BKC_REPO" =~ "gfx-driver-ci" ]]; then
        URL="https://gfx-assets-build.intel.com/artifactory/api/archive/download/gfx-driver-builds/ci/${branch%-*}/$CREATE_LOCAL_BKC_REPO/artifacts/Linux/Ubuntu/20.04?archiveType=tgz"
    else
        URL="https://gfx-assets-build.fm.intel.com/artifactory/api/archive/download/agama-builds/ci/${branch%-*}/$CREATE_LOCAL_BKC_REPO/artifacts/linux/ubuntu/20.04?archiveType=tgz"
    fi

    if ! curl -u "$USERNAME" -s --noproxy '*' -L          "${URL}" |
            tar -C ${WORKDIR} -xvz --warning=no-timestamp; then
        echo >&2 "Curl: failed to download release files"
        exit 0
    fi
    echo "done"

    echo "Creating local build repository..."
    pushd ${WORKDIR} > /dev/null
    dpkg-scanpackages .  > Packages
    popd > /dev/null
    echo "done"

    echo "Configuring local build repository..."
    if [ -f /etc/apt/sources.list.d/intel-graphics.list ]; then
        rm /etc/apt/sources.list.d/intel-graphics.list
    fi

    echo "deb [trusted=yes arch=amd64] file://${WORKDIR} ./" > /etc/apt/sources.list.d/intel-graphics.list
    apt -y update
    echo "done."
}

